#include <iostream>
#include <string>
using namespace std;

int main() {
  string firstName = "John";
  string lastName = "Doe";
  string fullName = firstName + " " + lastName;

  cout << "Full name: " << fullName << endl;
  cout << "Length: " << fullName.length() << endl;
  cout << "First char: " << fullName[0] << endl;
  return 0;
}
